525	  >
526	): void {
527	  const fields: string[] = [];
528	  const values: any[] = [];
529	
530	  const columnMap: Record<string, string> = {
531	    name: "name",
532	    color: "color",
533	    status: "status",
534	    totalTokens: "total_tokens",
