540	    model: "model",
541	  };
542	
543	  for (const [key, val] of Object.entries(updates)) {
544	    const col = columnMap[key];
545	    if (col && val !== undefined) {
546	      fields.push(`${col} = ?`);
547	      values.push(val);
548	    }
549	  }
550	
551	  if (fields.length === 0) return;
552	
553	  fields.push("updated_at = ?");
554	  values.push(Date.now());
555	  values.push(id);
556	
557	  getDb()
558	    .prepare(`UPDATE sessions SET ${fields.join(", ")} WHERE id = ?`)
559	    .run(...values);
560	}
