811	// src/shared/ipc.ts
812	
813	import net from "node:net";
814	import path from "node:path";
815	import { config } from "./config.js";
816	import type { Pin, StatusBarData, CompactEvent } from "./types.js";
817	
818	// --- Message Types ---
819	
820	// Shell → Worker
821	export type ShellToWorkerMessage =
822	  | { type: "send_prompt"; prompt: string; pins: Pin[] }
823	  | { type: "context_reset" }
824	  | { type: "context_snapshot" }
825	  | { type: "get_context_summary" }
826	  | {
827	      type: "set_worktree";
828	      worktreePath: string | null;
829	      branch: string | null;
830	    }
831	  | { type: "shutdown" };
832	
833	// Worker → Shell
834	export type WorkerToShellMessage =
835	  | { type: "ready"; workerId: string }
836	  | { type: "stream_chunk"; content: string }
837	  | { type: "message_complete"; role: string; content: string; tokens: number; cost: number }
838	  | { type: "context_compacted"; event: CompactEvent }
839	  | { type: "context_summary"; summary: string }
840	  | { type: "status_update"; data: Partial<StatusBarData> }
841	  | { type: "error"; message: string; fatal: boolean }
842	  | { type: "snapshot_complete"; filePath: string; summary: string };
843	
844	export type IPCMessage = ShellToWorkerMessage | WorkerToShellMessage;
845	
846	// --- Framing ---
847	// Length-prefixed JSON: 4-byte big-endian length + JSON payload
848	
849	const HEADER_SIZE = 4;
850	
851	export function encodeMessage(msg: IPCMessage): Buffer {
852	  const json = JSON.stringify(msg);
853	  const payload = Buffer.from(json, "utf-8");
854	  const header = Buffer.alloc(HEADER_SIZE);
855	  header.writeUInt32BE(payload.length, 0);
856	  return Buffer.concat([header, payload]);
857	}
858	
859	export class MessageDecoder {
860	  private buffer = Buffer.alloc(0);
861	
862	  feed(data: Buffer): IPCMessage[] {
863	    this.buffer = Buffer.concat([this.buffer, data]);
864	    const messages: IPCMessage[] = [];
865	
866	    while (this.buffer.length >= HEADER_SIZE) {
867	      const length = this.buffer.readUInt32BE(0);
868	      if (this.buffer.length < HEADER_SIZE + length) break;
869	
870	      const json = this.buffer.subarray(HEADER_SIZE, HEADER_SIZE + length).toString("utf-8");
871	      this.buffer = this.buffer.subarray(HEADER_SIZE + length);
872	
873	      try {
874	        messages.push(JSON.parse(json));
875	      } catch {
876	        // Skip malformed messages
877	      }
878	    }
879	
880	    return messages;
881	  }
882	}
883	
884	// --- Socket Helpers ---
885	
886	export function socketPath(workerId: string): string {
887	  return path.join(config.socketDir, `worker-${workerId}.sock`);
888	}
889	
890	export function sendMessage(socket: net.Socket, msg: IPCMessage): void {
891	  socket.write(encodeMessage(msg));
892	}
893	
894	export function createIPCServer(
895	  sockPath: string,
896	  onMessage: (msg: IPCMessage, socket: net.Socket) => void
897	): net.Server {
898	  const server = net.createServer((socket) => {
899	    const decoder = new MessageDecoder();
900	    socket.on("data", (data) => {
901	      for (const msg of decoder.feed(data)) {
902	        onMessage(msg, socket);
903	      }
904	    });
905	  });
906	
907	  server.listen(sockPath);
908	  return server;
909	}
910	
911	export function connectIPC(
912	  sockPath: string,
913	  onMessage: (msg: IPCMessage) => void
914	): Promise<net.Socket> {
915	  return new Promise((resolve, reject) => {
916	    const socket = net.createConnection(sockPath, () => {
917	      const decoder = new MessageDecoder();
918	      socket.on("data", (data) => {
919	        for (const msg of decoder.feed(data)) {
920	          onMessage(msg);
921	        }
922	      });
923	      resolve(socket);
924	    });
925	    socket.on("error", reject);
926	  });
927	}
