1000	// src/worker/claude-bridge.ts
1001	
1002	import { query, type SDKMessage } from "@anthropic-ai/claude-agent-sdk";
1003	import type { Pin, CompactEvent, StatusBarData } from "../shared/types.js";
1004	
1005	export interface BridgeCallbacks {
1006	  onStreamChunk: (content: string) => void;
1007	  onMessageComplete: (role: string, content: string, tokens: number, cost: number) => void;
1008	  onCompacted: (event: CompactEvent) => void;
1009	  onStatusUpdate: (data: Partial<StatusBarData>) => void;
1010	  onError: (message: string, fatal: boolean) => void;
1011	}
1012	
1013	export interface BridgeOptions {
1014	  cwd?: string;
1015	  model?: string;
1016	  sessionId?: string;
1017	  resume?: string;
1018	}
1019	
1020	export class ClaudeBridge {
1021	  private currentQuery: Awaited<ReturnType<typeof query>> | null = null;
1022	  private callbacks: BridgeCallbacks;
1023	  private options: BridgeOptions;
1024	  private claudeSessionId: string | null = null;
1025	
1026	  constructor(callbacks: BridgeCallbacks, options: BridgeOptions = {}) {
1027	    this.callbacks = callbacks;
1028	    this.options = options;
1029	  }
1030	
1031	  async sendPrompt(prompt: string, pins: Pin[]): Promise<void> {
1032	    const systemPromptParts: string[] = [];
1033	
1034	    // Resolve pins into context
1035	    for (const pin of pins) {
1036	      if (pin.type === "file") {
1037	        systemPromptParts.push(`[Pinned file: ${pin.target}]`);
1038	      } else if (pin.type === "skill") {
1039	        systemPromptParts.push(`[Active skill: ${pin.target}]`);
1040	      } else if (pin.type === "command") {
1041	        systemPromptParts.push(`[Command: ${pin.target}]`);
1042	      }
1043	    }
1044	
1045	    const fullPrompt = systemPromptParts.length > 0
1046	      ? `${systemPromptParts.join("\n")}\n\n${prompt}`
1047	      : prompt;
1048	
1049	    try {
1050	      const queryOptions: Record<string, any> = {
1051	        allowedTools: ["Read", "Edit", "Write", "Bash", "Glob", "Grep"],
1052	        includePartialMessages: true,
1053	      };
1054	
1055	      if (this.options.cwd) queryOptions.cwd = this.options.cwd;
1056	      if (this.options.model) queryOptions.model = this.options.model;
1057	
1058	      // Resume existing session or start new
1059	      if (this.claudeSessionId) {
1060	        queryOptions.resume = this.claudeSessionId;
1061	      } else if (this.options.resume) {
1062	        queryOptions.resume = this.options.resume;
1063	      }
1064	
1065	      this.currentQuery = query({ prompt: fullPrompt, options: queryOptions });
1066	
1067	      for await (const msg of this.currentQuery) {
1068	        this.handleMessage(msg);
1069	      }
1070	    } catch (err: any) {
1071	      this.callbacks.onError(err.message || "Unknown error", false);
1072	    } finally {
1073	      this.currentQuery = null;
1074	    }
1075	  }
1076	
1077	  private handleMessage(msg: SDKMessage): void {
1078	    // Type narrowing based on message structure
1079	    if ("type" in msg) {
1080	      switch (msg.type) {
1081	        case "system":
1082	          if ("subtype" in msg && msg.subtype === "init") {
1083	            this.claudeSessionId = (msg as any).session_id ?? null;
1084	            this.callbacks.onStatusUpdate({
1085	              model: (msg as any).model ?? null,
1086	              sessionId: this.claudeSessionId,
1087	            });
1088	          }
1089	          if ("subtype" in msg && msg.subtype === "compact_boundary") {
1090	            const meta = (msg as any).compact_metadata;
1091	            this.callbacks.onCompacted({
1092	              timestamp: Date.now(),
1093	              trigger: meta?.trigger ?? "auto",
1094	              preTokens: meta?.pre_tokens ?? 0,
1095	            });
1096	          }
