2178	// src/shell/hooks/useWorkerManager.ts
2179	
2180	import { useEffect, useRef, useCallback } from "react";
2181	import { fork, type ChildProcess } from "node:child_process";
2182	import fs from "node:fs";
2183	import net from "node:net";
2184	import { v4 as uuid } from "uuid";
2185	import { useStore } from "../store/index.js";
2186	import {
2187	  createIPCServer,
2188	  sendMessage,
2189	  socketPath,
2190	  type IPCMessage,
2191	  type WorkerToShellMessage,
2192	  type ShellToWorkerMessage,
2193	} from "../../shared/ipc.js";
2194	import { config, ensureDirs } from "../../shared/config.js";
2195	import type { Pin } from "../../shared/types.js";
2196	
2197	interface WorkerHandle {
2198	  process: ChildProcess;
2199	  socket: net.Socket | null;

2200	  server: net.Server;
2201	  workerId: string;
2202	  tabId: string;
2203	}
2204	
2205	export function useWorkerManager(cwd: string) {
2206	  const workersRef = useRef<Map<string, WorkerHandle>>(new Map());
2207	
2208	  const spawnWorker = useCallback(
2209	    (tabId: string): string => {
2210	      ensureDirs();
2211	      const workerId = uuid();
2212	      const sockPath = socketPath(workerId);
2213	
2214	      // Clean up stale socket
2215	      try {
2216	        fs.unlinkSync(sockPath);
2217	      } catch {}
2218	
2219	      // Create IPC server for this worker
2220	      const server = createIPCServer(sockPath, (msg, socket) => {
2221	        const handle = workersRef.current.get(tabId);
2222	        if (handle && !handle.socket) {
2223	          handle.socket = socket;
2224	        }
2225	        handleWorkerMessage(tabId, msg as WorkerToShellMessage);
2226	      });
2227	
2228	      // Fork worker process
2229	      const workerProcess = fork(config.workerEntry, [workerId, cwd], {
2230	        stdio: "pipe",
2231	        env: { ...process.env },
2232	      });
2233	
2234	      workerProcess.on("exit", (code) => {
2235	        cleanupWorker(tabId);
2236	        if (code !== 0) {
2237	          useStore.getState().appendMessage(tabId, {
2238	            id: uuid(),
2239	            sessionId: tabId,
2240	            role: "system",
2241	            content: `Worker exited with code ${code}`,
2242	            tokens: 0,
2243	            cost: 0,
2244	            createdAt: Date.now(),
2245	          });
2246	        }
2247	      });
2248	
2249	      workersRef.current.set(tabId, {
2250	        process: workerProcess,
2251	        socket: null,
2252	        server,
2253	        workerId,
2254	        tabId,
2255	      });
2256	
2257	      return workerId;
2258	    },
2259	    [cwd]
2260	  );
2261	
2262	  function handleWorkerMessage(tabId: string, msg: WorkerToShellMessage): void {
2263	    const store = useStore.getState();
2264	
2265	    switch (msg.type) {
2266	      case "ready":
2267	        store.setWorkerReady(tabId, msg.workerId);
2268	        break;
2269	
2270	      case "stream_chunk":
2271	        store.appendStreamBuffer(tabId, msg.content);
2272	        break;
2273	
2274	      case "message_complete":
2275	        store.clearStreamBuffer(tabId);
2276	        store.appendMessage(tabId, {
2277	          id: uuid(),
2278	          sessionId: tabId,
2279	          role: msg.role as any,
2280	          content: msg.content,
2281	          tokens: msg.tokens,
2282	          cost: msg.cost,
2283	          createdAt: Date.now(),
2284	        });
2285	        break;
2286	
2287	      case "status_update":
2288	        store.updateTabStatus(tabId, msg.data);
2289	        break;
2290	
2291	      case "context_compacted":
2292	        store.addCompactEvent(tabId, msg.event);
2293	        break;
2294	
2295	      case "error":
2296	        store.appendMessage(tabId, {
2297	          id: uuid(),
2298	          sessionId: tabId,
2299	          role: "system",
2300	          content: `Error: ${msg.message}`,
2301	          tokens: 0,
2302	          cost: 0,
2303	          createdAt: Date.now(),
2304	        });
2305	        break;
2306	    }
2307	  }
2308	
2309	  function sendToWorker(tabId: string, msg: ShellToWorkerMessage): void {
2310	    const handle = workersRef.current.get(tabId);
2311	    if (handle?.socket) {
2312	      sendMessage(handle.socket, msg);
2313	    }
2314	  }
2315	
2316	  function killWorker(tabId: string): void {
2317	    const handle = workersRef.current.get(tabId);
2318	    if (handle) {
2319	      sendToWorker(tabId, { type: "shutdown" });
2320	      setTimeout(() => {
2321	        handle.process.kill("SIGTERM");
2322	        cleanupWorker(tabId);
2323	      }, 2000);
2324	    }
2325	  }
2326	
2327	  function cleanupWorker(tabId: string): void {
2328	    const handle = workersRef.current.get(tabId);
2329	    if (handle) {
2330	      handle.socket?.destroy();
2331	      handle.server.close();
2332	      try {
2333	        fs.unlinkSync(socketPath(handle.workerId));
2334	      } catch {}
2335	      workersRef.current.delete(tabId);
2336	    }
2337	  }
2338	
2339	  // Cleanup all workers on unmount
2340	  useEffect(() => {
2341	    return () => {
2342	      for (const [tabId] of workersRef.current) {
2343	        killWorker(tabId);
2344	      }
2345	    };
2346	  }, []);
2347	
2348	  return {
2349	    spawnWorker,
2350	    sendToWorker,
2351	    killWorker,
2352	    sendPrompt: (tabId: string, prompt: string, pins: Pin[]) => {
2353	      const store = useStore.getState();
2354	      // Add user message to store
2355	      store.appendMessage(tabId, {
2356	        id: uuid(),
2357	        sessionId: tabId,
2358	        role: "user",
2359	        content: prompt,
2360	        tokens: 0,
2361	        cost: 0,
2362	        createdAt: Date.now(),
2363	      });
2364	      // Send to worker
2365	      sendToWorker(tabId, { type: "send_prompt", prompt, pins });
2366	    },
2367	  };
2368	}
