}

export function App({ args }: AppProps): React.ReactElement {
  const createTab = useStore((s) => s.createTab);
  const activeTabId = useStore((s) => s.activeTabId);
  const tabs = useStore((s) => s.tabs);
  const [initialized, setInitialized] = useState(false);

  const { spawnWorker, sendPrompt, killWorker } = useWorkerManager(args.cwd);

  // Create initial tab and spawn its worker
  useEffect(() => {
    if (!initialized) {
      const tab = createTab("New Session");
      spawnWorker(tab.id);
      setInitialized(true);
    }
  }, [initialized, createTab, spawnWorker]);

  // Spawn worker when new tab is created (watch for tabs without workers)
  useEffect(() => {
    for (const tab of tabs) {
      if (!tab.workerId && !tab.workerReady) {
        spawnWorker(tab.id);
      }
    }
  }, [tabs, spawnWorker]);

  function handleSubmit(text: string): void {
    if (!activeTabId) return;
    sendPrompt(activeTabId, text, []);
  }

  function handleCloseTab(tabId: string): void {
    killWorker(tabId);
    useStore.getState().closeTab(tabId);
  }

  return (
    <Layout
      sessionSidebar={
        <Box flexDirection="column" padding={1}>
          <Text bold color="cyan">Sessions</Text>
