          <TabBar />
          <ChatView />
          <ContextBar pins={[]} onRemovePin={() => {}} />
          <InputBar onSubmit={handleSubmit} />
          <StatusBar />
        </Box>
      }
      skillsSidebar={
        <Box flexDirection="column" padding={1}>
          <Text bold color="cyan">Skills</Text>
          <Text color="gray">Phase 4</Text>
        </Box>
      }
    />
  );
}
