import Database from "better-sqlite3";
import fs from "node:fs";
import path from "node:path";
import { config, ensureDirs } from "./config.js";
import type { Session, Message, Pin, Snapshot } from "./types.js";

let db: Database.Database | null = null;

export function getDb(): Database.Database {
  if (db) return db;

  ensureDirs();
  db = new Database(config.dbPath);
  db.pragma("journal_mode = WAL");
  db.pragma("foreign_keys = ON");
  runMigrations(db);
  return db;
}

function runMigrations(database: Database.Database): void {
  const migrationsDir = path.join(import.meta.dirname, "../../db/migrations");
  const files = fs.readdirSync(migrationsDir).sort();

  database.exec(`
    CREATE TABLE IF NOT EXISTS _migrations (
      name TEXT PRIMARY KEY,
      applied_at INTEGER NOT NULL
    )
  `);

  const applied = new Set(
    database
      .prepare("SELECT name FROM _migrations")
      .all()
      .map((row: any) => row.name)
  );

  for (const file of files) {
    if (applied.has(file)) continue;
    const sql = fs.readFileSync(path.join(migrationsDir, file), "utf-8");
    database.exec(sql);
    database
      .prepare("INSERT INTO _migrations (name, applied_at) VALUES (?, ?)")
      .run(file, Date.now());
  }
}

// --- Sessions ---

export function createSession(session: Session): void {
  getDb()
    .prepare(
      `INSERT INTO sessions (id, claude_session_id, name, color, repo_path, worktree_path, worktree_branch, model, total_tokens, total_cost, duration_seconds, status, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
    )
    .run(
      session.id,
      session.claudeSessionId,
      session.name,
      session.color,
      session.repoPath,
      session.worktreePath,
      session.worktreeBranch,
      session.model,
      session.totalTokens,
      session.totalCost,
      session.durationSeconds,
      session.status,
      session.createdAt,
      session.updatedAt
    );
}

export function updateSession(
  id: string,
  updates: Partial<
    Pick<Session, "name" | "color" | "status" | "totalTokens" | "totalCost" | "durationSeconds" | "claudeSessionId" | "worktreePath" | "worktreeBranch" | "model">
  >
): void {
  const fields: string[] = [];
  const values: any[] = [];

  const columnMap: Record<string, string> = {
    name: "name",
    color: "color",
    status: "status",
    totalTokens: "total_tokens",
    totalCost: "total_cost",
    durationSeconds: "duration_seconds",
    claudeSessionId: "claude_session_id",
    worktreePath: "worktree_path",
    worktreeBranch: "worktree_branch",
    model: "model",
  };

  for (const [key, val] of Object.entries(updates)) {
    const col = columnMap[key];
    if (col && val !== undefined) {
      fields.push(`${col} = ?`);
      values.push(val);
    }
  }

  if (fields.length === 0) return;

  fields.push("updated_at = ?");
  values.push(Date.now());
  values.push(id);

  getDb()
    .prepare(`UPDATE sessions SET ${fields.join(", ")} WHERE id = ?`)
    .run(...values);
}

export function listSessions(limit = 50): Session[] {
  return getDb()
    .prepare(
      `SELECT id, claude_session_id as claudeSessionId, name, color, repo_path as repoPath,
              worktree_path as worktreePath, worktree_branch as worktreeBranch, model,
              total_tokens as totalTokens, total_cost as totalCost,
              duration_seconds as durationSeconds, status, created_at as createdAt,
              updated_at as updatedAt
       FROM sessions ORDER BY updated_at DESC LIMIT ?`
    )
    .all(limit) as Session[];
}

export function getSession(id: string): Session | undefined {
  return getDb()
    .prepare(
      `SELECT id, claude_session_id as claudeSessionId, name, color, repo_path as repoPath,
              worktree_path as worktreePath, worktree_branch as worktreeBranch, model,
              total_tokens as totalTokens, total_cost as totalCost,
              duration_seconds as durationSeconds, status, created_at as createdAt,
              updated_at as updatedAt
       FROM sessions WHERE id = ?`
    )
    .get(id) as Session | undefined;
}

// --- Messages ---

export function addMessage(msg: Message): void {
  getDb()
    .prepare(
      `INSERT INTO messages (id, session_id, role, content, tokens, cost, created_at)
       VALUES (?, ?, ?, ?, ?, ?, ?)`
    )
    .run(msg.id, msg.sessionId, msg.role, msg.content, msg.tokens, msg.cost, msg.createdAt);
}

export function getMessages(sessionId: string, limit = 100, offset = 0): Message[] {
  return getDb()
    .prepare(
      `SELECT id, session_id as sessionId, role, content, tokens, cost, created_at as createdAt
       FROM messages WHERE session_id = ? ORDER BY created_at ASC LIMIT ? OFFSET ?`
    )
    .all(sessionId, limit, offset) as Message[];
}

// --- Pins ---

export function addPin(pin: Pin): void {
  getDb()
    .prepare(
      `INSERT INTO pins (id, session_id, type, target, mode, created_at)
       VALUES (?, ?, ?, ?, ?, ?)`
    )
    .run(pin.id, pin.sessionId, pin.type, pin.target, pin.mode, pin.createdAt);
}

export function removePinById(id: string): void {
  getDb().prepare("DELETE FROM pins WHERE id = ?").run(id);
}

export function getPins(sessionId: string): Pin[] {
  return getDb()
    .prepare(
      `SELECT id, session_id as sessionId, type, target, mode, created_at as createdAt
       FROM pins WHERE session_id = ?`
    )
    .all(sessionId) as Pin[];
}

export function clearOneShots(sessionId: string): void {
  getDb()
    .prepare("DELETE FROM pins WHERE session_id = ? AND mode = 'prompt'")
    .run(sessionId);
}

// --- Snapshots ---

export function addSnapshot(snap: Snapshot): void {
  getDb()
    .prepare(
      `INSERT INTO snapshots (id, session_id, summary, context_state, file_path, created_at)
       VALUES (?, ?, ?, ?, ?, ?)`
    )
    .run(snap.id, snap.sessionId, snap.summary, snap.contextState, snap.filePath, snap.createdAt);
}

// --- Settings ---

export function getSetting<T>(key: string, fallback: T): T {
  const row = getDb().prepare("SELECT value FROM settings WHERE key = ?").get(key) as
    | { value: string }
    | undefined;
  if (!row) return fallback;
  try {
    return JSON.parse(row.value) as T;
  } catch {
    return fallback;
  }
}

export function setSetting<T>(key: string, value: T): void {
  getDb()
    .prepare("INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)")
    .run(key, JSON.stringify(value));
}

export function closeDb(): void {
  if (db) {
    db.close();
    db = null;
  }
}
