import { query, type SDKMessage } from "@anthropic-ai/claude-agent-sdk";
import type { Pin, CompactEvent, StatusBarData } from "../shared/types.js";

export interface BridgeCallbacks {
  onStreamChunk: (content: string) => void;
  onMessageComplete: (role: string, content: string, tokens: number, cost: number) => void;
  onCompacted: (event: CompactEvent) => void;
  onStatusUpdate: (data: Partial<StatusBarData>) => void;
  onError: (message: string, fatal: boolean) => void;
}

export interface BridgeOptions {
  cwd?: string;
  model?: string;
  sessionId?: string;
  resume?: string;
}

export class ClaudeBridge {
  private currentQuery: Awaited<ReturnType<typeof query>> | null = null;
  private callbacks: BridgeCallbacks;
  private options: BridgeOptions;
  private claudeSessionId: string | null = null;

  constructor(callbacks: BridgeCallbacks, options: BridgeOptions = {}) {
    this.callbacks = callbacks;
    this.options = options;
  }

  async sendPrompt(prompt: string, pins: Pin[]): Promise<void> {
    const systemPromptParts: string[] = [];

    for (const pin of pins) {
      if (pin.type === "file") {
        systemPromptParts.push(`[Pinned file: ${pin.target}]`);
      } else if (pin.type === "skill") {
        systemPromptParts.push(`[Active skill: ${pin.target}]`);
      } else if (pin.type === "command") {
        systemPromptParts.push(`[Command: ${pin.target}]`);
      }
    }

    const fullPrompt = systemPromptParts.length > 0
      ? `${systemPromptParts.join("\n")}\n\n${prompt}`
      : prompt;

    try {
      const queryOptions: Record<string, any> = {
        allowedTools: ["Read", "Edit", "Write", "Bash", "Glob", "Grep"],
        includePartialMessages: true,
      };

      if (this.options.cwd) queryOptions.cwd = this.options.cwd;
      if (this.options.model) queryOptions.model = this.options.model;

      if (this.claudeSessionId) {
        queryOptions.resume = this.claudeSessionId;
      } else if (this.options.resume) {
        queryOptions.resume = this.options.resume;
      }

      this.currentQuery = query({ prompt: fullPrompt, options: queryOptions });

      for await (const msg of this.currentQuery) {
        this.handleMessage(msg);
      }
    } catch (err: any) {
      this.callbacks.onError(err.message || "Unknown error", false);
    } finally {
      this.currentQuery = null;
    }
  }

  private handleMessage(msg: SDKMessage): void {
    if ("type" in msg) {
      switch (msg.type) {
        case "system":
          if ("subtype" in msg && msg.subtype === "init") {
            this.claudeSessionId = (msg as any).session_id ?? null;
            this.callbacks.onStatusUpdate({
              model: (msg as any).model ?? null,
              sessionId: this.claudeSessionId,
            });
          }
          if ("subtype" in msg && msg.subtype === "compact_boundary") {
            const meta = (msg as any).compact_metadata;
            this.callbacks.onCompacted({
              timestamp: Date.now(),
              trigger: meta?.trigger ?? "auto",
              preTokens: meta?.pre_tokens ?? 0,
            });
          }
          break;

        case "assistant": {
          const assistantMsg = msg as any;
          const content = assistantMsg.message?.content
            ?.filter((b: any) => b.type === "text")
            .map((b: any) => b.text)
            .join("") ?? "";
          const usage = assistantMsg.message?.usage;
          const tokens = (usage?.input_tokens ?? 0) + (usage?.output_tokens ?? 0);
          this.callbacks.onMessageComplete("assistant", content, tokens, 0);
          break;
        }

        case "stream_event": {
          const event = (msg as any).event;
          if (event?.type === "content_block_delta" && event.delta?.type === "text_delta") {
            this.callbacks.onStreamChunk(event.delta.text);
          }
          break;
        }

        case "result": {
          const result = msg as any;
          this.callbacks.onStatusUpdate({
            sessionId: result.session_id ?? this.claudeSessionId,
          });
          if (result.subtype === "error_during_execution") {
            this.callbacks.onError(result.error ?? "Execution error", false);
          }
          break;
        }
      }
    }
  }

  interrupt(): void {
    this.currentQuery?.interrupt();
  }

  getSessionId(): string | null {
    return this.claudeSessionId;
  }
}
