import React from "react";
import { Box, Text, useInput } from "ink";
import { useStore } from "../store/index.js";

export function TabBar(): React.ReactElement {
  const tabs = useStore((s) => s.tabs);
  const activeTabId = useStore((s) => s.activeTabId);
  const setActiveTab = useStore((s) => s.setActiveTab);
  const createTab = useStore((s) => s.createTab);
  const closeTab = useStore((s) => s.closeTab);

  useInput((input, key) => {
    if (input === "t" && key.ctrl) {
      createTab();
      return;
    }

    if (input === "w" && key.ctrl && activeTabId) {
      closeTab(activeTabId);
      return;
    }

    if (key.ctrl && input >= "1" && input <= "9") {
      const idx = parseInt(input, 10) - 1;
      if (tabs[idx]) {
        setActiveTab(tabs[idx].id);
      }
      return;
    }

    if (key.tab && !key.shift && tabs.length > 1) {
      const currentIdx = tabs.findIndex((t) => t.id === activeTabId);
      const nextIdx = (currentIdx + 1) % tabs.length;
      setActiveTab(tabs[nextIdx].id);
    }
  });

  return (
    <Box flexDirection="row" borderStyle="single" borderColor="gray" borderBottom={false}>
      {tabs.map((tab) => (
        <Box key={tab.id} paddingX={1}>
          <Text
            color={tab.id === activeTabId ? "cyan" : "gray"}
            bold={tab.id === activeTabId}
          >
            {tab.index}: {tab.name}
          </Text>
        </Box>
      ))}
      <Box paddingX={1}>
        <Text color="green">[+]</Text>
      </Box>
    </Box>
  );
}

