import net from "node:net";
import path from "node:path";
import { config } from "./config.js";
import type { Pin, StatusBarData, CompactEvent } from "./types.js";

// Shell -> Worker
export type ShellToWorkerMessage =
  | { type: "send_prompt"; prompt: string; pins: Pin[] }
  | { type: "context_reset" }
  | { type: "context_snapshot" }
  | { type: "get_context_summary" }
  | { type: "set_worktree"; worktreePath: string | null; branch: string | null }
  | { type: "shutdown" };

// Worker -> Shell
export type WorkerToShellMessage =
  | { type: "ready"; workerId: string }
  | { type: "stream_chunk"; content: string }
  | { type: "message_complete"; role: string; content: string; tokens: number; cost: number }
  | { type: "context_compacted"; event: CompactEvent }
  | { type: "context_summary"; summary: string }
  | { type: "status_update"; data: Partial<StatusBarData> }
  | { type: "error"; message: string; fatal: boolean }
  | { type: "snapshot_complete"; filePath: string; summary: string };

export type IPCMessage = ShellToWorkerMessage | WorkerToShellMessage;

const HEADER_SIZE = 4;

export function encodeMessage(msg: IPCMessage): Buffer {
  const json = JSON.stringify(msg);
  const payload = Buffer.from(json, "utf-8");
  const header = Buffer.alloc(HEADER_SIZE);
  header.writeUInt32BE(payload.length, 0);
  return Buffer.concat([header, payload]);
}

export class MessageDecoder {
  private buffer = Buffer.alloc(0);

  feed(data: Buffer): IPCMessage[] {
    this.buffer = Buffer.concat([this.buffer, data]);
    const messages: IPCMessage[] = [];

    while (this.buffer.length >= HEADER_SIZE) {
      const length = this.buffer.readUInt32BE(0);
      if (this.buffer.length < HEADER_SIZE + length) break;

      const json = this.buffer.subarray(HEADER_SIZE, HEADER_SIZE + length).toString("utf-8");
      this.buffer = this.buffer.subarray(HEADER_SIZE + length);

      try {
        messages.push(JSON.parse(json));
      } catch {
        // Skip malformed messages
      }
    }

    return messages;
  }
}

export function socketPath(workerId: string): string {
  return path.join(config.socketDir, `worker-${workerId}.sock`);
}

export function sendMessage(socket: net.Socket, msg: IPCMessage): void {
  socket.write(encodeMessage(msg));
}

export function createIPCServer(
  sockPath: string,
  onMessage: (msg: IPCMessage, socket: net.Socket) => void
): net.Server {
  const server = net.createServer((socket) => {
    const decoder = new MessageDecoder();
    socket.on("data", (data) => {
      for (const msg of decoder.feed(data)) {
        onMessage(msg, socket);
      }
    });
  });

  server.listen(sockPath);
  return server;
}

export function connectIPC(
  sockPath: string,
  onMessage: (msg: IPCMessage) => void
): Promise<net.Socket> {
  return new Promise((resolve, reject) => {
    const socket = net.createConnection(sockPath, () => {
      const decoder = new MessageDecoder();
      socket.on("data", (data) => {
        for (const msg of decoder.feed(data)) {
          onMessage(msg);
        }
      });
      resolve(socket);
    });
    socket.on("error", reject);
  });
}

