import { describe, it, expect, beforeEach, afterEach } from "vitest";
import Database from "better-sqlite3";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";
import { v4 as uuid } from "uuid";

function createTestDb(): Database.Database {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "clui-test-"));
  const dbPath = path.join(tmpDir, "test.db");
  const db = new Database(dbPath);
  db.pragma("journal_mode = WAL");
  db.pragma("foreign_keys = ON");

  const migrationPath = path.join(
    import.meta.dirname,
    "../../db/migrations/001_init.sql"
  );
  const sql = fs.readFileSync(migrationPath, "utf-8");
  db.exec(sql);

  return db;
}

describe("database", () => {
  let db: Database.Database;

  beforeEach(() => {
    db = createTestDb();
  });

  afterEach(() => {
    db.close();
  });

  it("creates all tables", () => {
    const tables = db
      .prepare("SELECT name FROM sqlite_master WHERE type='table'")
      .all()
      .map((r: any) => r.name);
    expect(tables).toContain("sessions");
    expect(tables).toContain("messages");
    expect(tables).toContain("pins");
    expect(tables).toContain("snapshots");
    expect(tables).toContain("settings");
  });

  it("inserts and retrieves a session", () => {
    const id = uuid();
    const now = Date.now();
    db.prepare(
      `INSERT INTO sessions (id, name, status, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?)`
    ).run(id, "test session", "active", now, now);

    const row = db
      .prepare("SELECT * FROM sessions WHERE id = ?")
      .get(id) as any;
    expect(row.name).toBe("test session");
    expect(row.status).toBe("active");
  });

  it("cascades message delete on session delete", () => {
    const sessionId = uuid();
    const msgId = uuid();
    const now = Date.now();

    db.prepare(
      "INSERT INTO sessions (id, name, status, created_at, updated_at) VALUES (?, ?, ?, ?, ?)"
    ).run(sessionId, "s", "active", now, now);

    db.prepare(
      "INSERT INTO messages (id, session_id, role, content, created_at) VALUES (?, ?, ?, ?, ?)"
    ).run(msgId, sessionId, "user", "hello", now);

    db.prepare("DELETE FROM sessions WHERE id = ?").run(sessionId);

    const msg = db.prepare("SELECT * FROM messages WHERE id = ?").get(msgId);
    expect(msg).toBeUndefined();
  });

  it("stores and retrieves settings as JSON", () => {
    db.prepare("INSERT INTO settings (key, value) VALUES (?, ?)").run(
      "theme",
      JSON.stringify({ dark: true })
    );

    const row = db
      .prepare("SELECT value FROM settings WHERE key = ?")
      .get("theme") as any;
    expect(JSON.parse(row.value)).toEqual({ dark: true });
  });
});

