import { describe, it, expect } from "vitest";
import { encodeMessage, MessageDecoder } from "../../src/shared/ipc.js";
import type { IPCMessage } from "../../src/shared/ipc.js";

describe("IPC framing", () => {
  it("encodes and decodes a single message", () => {
    const msg: IPCMessage = { type: "ready", workerId: "w1" };
    const encoded = encodeMessage(msg);
    const decoder = new MessageDecoder();
    const decoded = decoder.feed(encoded);
    expect(decoded).toEqual([msg]);
  });

  it("handles multiple messages in one buffer", () => {
    const msg1: IPCMessage = { type: "ready", workerId: "w1" };
    const msg2: IPCMessage = { type: "stream_chunk", content: "hello" };
    const buf = Buffer.concat([encodeMessage(msg1), encodeMessage(msg2)]);
    const decoder = new MessageDecoder();
    const decoded = decoder.feed(buf);
    expect(decoded).toEqual([msg1, msg2]);
  });

  it("handles partial messages across feeds", () => {
    const msg: IPCMessage = { type: "stream_chunk", content: "world" };
    const full = encodeMessage(msg);
    const decoder = new MessageDecoder();

    const mid = Math.floor(full.length / 2);
    const part1 = decoder.feed(full.subarray(0, mid));
    expect(part1).toEqual([]);

    const part2 = decoder.feed(full.subarray(mid));
    expect(part2).toEqual([msg]);
  });
});

