import { describe, it, expect, beforeEach } from "vitest";
import { create } from "zustand";
import { createTabsSlice, type TabsSlice } from "../../../src/shell/store/tabs.js";

function createTestStore() {
  return create<TabsSlice>((set, get) => ({
    ...createTabsSlice(set, get),
  }));
}

describe("tabs store", () => {
  let useStore: ReturnType<typeof createTestStore>;

  beforeEach(() => {
    useStore = createTestStore();
  });

  it("creates a tab with correct index", () => {
    const tab = useStore.getState().createTab("Test");
    expect(tab.name).toBe("Test");
    expect(tab.index).toBe(1);
    expect(useStore.getState().tabs).toHaveLength(1);
    expect(useStore.getState().activeTabId).toBe(tab.id);
  });

  it("auto-increments tab index", () => {
    const t1 = useStore.getState().createTab();
    const t2 = useStore.getState().createTab();
    expect(t1.index).toBe(1);
    expect(t2.index).toBe(2);
  });

  it("closes a tab and selects the last remaining", () => {
    const t1 = useStore.getState().createTab("A");
    const t2 = useStore.getState().createTab("B");
    useStore.getState().setActiveTab(t1.id);
    useStore.getState().closeTab(t1.id);
    expect(useStore.getState().tabs).toHaveLength(1);
    expect(useStore.getState().activeTabId).toBe(t2.id);
  });

  it("appends stream buffer chunks", () => {
    const tab = useStore.getState().createTab();
    useStore.getState().appendStreamBuffer(tab.id, "hello ");
    useStore.getState().appendStreamBuffer(tab.id, "world");
    expect(useStore.getState().tabStreamBuffer[tab.id]).toBe("hello world");
  });

  it("clears stream buffer", () => {
    const tab = useStore.getState().createTab();
    useStore.getState().appendStreamBuffer(tab.id, "data");
    useStore.getState().clearStreamBuffer(tab.id);
    expect(useStore.getState().tabStreamBuffer[tab.id]).toBe("");
  });

  it("updates tab status partially", () => {
    const tab = useStore.getState().createTab();
    useStore.getState().updateTabStatus(tab.id, { model: "opus", cost: 0.5 });
    const status = useStore.getState().tabStatus[tab.id];
    expect(status.model).toBe("opus");
    expect(status.cost).toBe(0.5);
    expect(status.contextTokens).toBe(0);
  });

  it("renames a tab", () => {
    const tab = useStore.getState().createTab("Old");
    useStore.getState().renameTab(tab.id, "New");
    expect(useStore.getState().tabs[0].name).toBe("New");
  });
});

