interface SessionSidebarProps {
  onOpenSession: (session: Session) => void;
  visible: boolean;
}

const COLORS = ["red", "green", "yellow", "blue", "magenta", "cyan", "white"];

function formatDate(ts: number): string {
  const d = new Date(ts);
  const month = (d.getMonth() + 1).toString().padStart(2, "0");
  const day = d.getDate().toString().padStart(2, "0");
  return `${month}/${day}`;
}

function formatCost(cost: number): string {
  if (cost === 0) return "";
  return `$${cost.toFixed(2)}`;
}

export function SessionSidebar({
  onOpenSession,
  visible,
}: SessionSidebarProps): React.ReactElement {
  const sessions = useStore((s) => s.sessions);
  const sessionFilter = useStore((s) => s.sessionFilter);
  const setSessionFilter = useStore((s) => s.setSessionFilter);
  const filteredSessions = useStore((s) => s.filteredSessions);
  const updateSessionColor = useStore((s) => s.updateSessionColor);
  const updateSessionName = useStore((s) => s.updateSessionName);

  const [selectedIdx, setSelectedIdx] = useState(0);
  const [renaming, setRenaming] = useState<string | null>(null);
  const [renameValue, setRenameValue] = useState("");

  const filtered = filteredSessions();

  useInput(
    (input, key) => {
      if (!visible) return;

      if (key.upArrow) {
        setSelectedIdx((i) => Math.max(0, i - 1));
        return;
      }
      if (key.downArrow) {
        setSelectedIdx((i) => Math.min(filtered.length - 1, i + 1));
        return;
      }
      if (key.return && filtered[selectedIdx]) {
        if (renaming) return;
        onOpenSession(filtered[selectedIdx]);
        return;
      }
      // 'r' to rename
      if (input === "r" && !renaming && filtered[selectedIdx]) {
        setRenaming(filtered[selectedIdx].id);
        setRenameValue(filtered[selectedIdx].name);
        return;
      }
      // 'c' to cycle color
      if (input === "c" && filtered[selectedIdx]) {
        const session = filtered[selectedIdx];
        const currentIdx = COLORS.indexOf(session.color || "");
        const nextColor = COLORS[(currentIdx + 1) % COLORS.length];
        updateSessionColor(session.id, nextColor);
        return;
      }
    },
    { isActive: visible }
  );

  function handleRenameSubmit(value: string): void {
    if (renaming && value.trim()) {
      updateSessionName(renaming, value.trim());
    }
    setRenaming(null);
    setRenameValue("");
  }

  if (!visible) return <></>;

  return (
    <Box flexDirection="column" padding={1}>
      <Text bold color="cyan">
        Sessions
      </Text>

      <Box marginY={1}>
        <Text color="gray">🔍 </Text>
        <TextInput
          value={sessionFilter}
          onChange={setSessionFilter}
          placeholder="Filter..."
          focus={visible && !renaming}
        />
      </Box>

      {filtered.map((session, idx) => {
        const isSelected = idx === selectedIdx;
        const isRenaming = renaming === session.id;

        return (
          <Box key={session.id} flexDirection="row">
            <Text color={session.color || "white"}>
              {isSelected ? "▸ " : "  "}●{" "}
            </Text>
            {isRenaming ? (
              <TextInput
                value={renameValue}
                onChange={setRenameValue}
                onSubmit={handleRenameSubmit}
                focus={true}
              />
            ) : (
              <Text
                color={isSelected ? "white" : "gray"}
                bold={isSelected}
              >
                {session.name}
              </Text>
            )}
            <Text color="gray">
              {" "}
              {formatDate(session.updatedAt)}
              {formatCost(session.totalCost) && ` ${formatCost(session.totalCost)}`}
            </Text>
          </Box>
        );
      })}

      {filtered.length === 0 && (
        <Text color="gray">No sessions found</Text>
      )}

      <Box marginTop={1}>
        <Text color="gray" dimColor>
          ↑↓ navigate · Enter open · r rename · c color
        </Text>
      </Box>
    </Box>
  );
}
