// src/shell/store/skills.ts

import type { Skill, SkillTier } from "../../shared/types.js";

export interface SkillsSlice {
  skills: Skill[];
  expandedTiers: Record<SkillTier, boolean>;
  setSkills: (skills: Skill[]) => void;
  toggleTier: (tier: SkillTier) => void;
  getSkillsByTier: (tier: SkillTier) => Skill[];
}

export function createSkillsSlice(
  set: (fn: (state: any) => any) => void,
  get: () => any
): SkillsSlice {
  return {
    skills: [],
    expandedTiers: { repo: true, user: false, global: false },

    setSkills: (skills: Skill[]) => set(() => ({ skills })),

    toggleTier: (tier: SkillTier) => {
      set((s: any) => ({
        expandedTiers: {
          ...s.expandedTiers,
          [tier]: !s.expandedTiers[tier],
        },
      }));
    },

    getSkillsByTier: (tier: SkillTier) => {
      return get().skills.filter((s: Skill) => s.tier === tier);
    },
  };
}
