import { config } from "../../shared/config.js";
import type { Skill, SkillTier } from "../../shared/types.js";

function scanSkillDir(dir: string, tier: SkillTier): Skill[] {
  const skills: Skill[] = [];

  try {
    if (!fs.existsSync(dir)) return skills;

    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isFile() && entry.name.endsWith(".md")) {
        const filePath = path.join(dir, entry.name);
        const content = fs.readFileSync(filePath, "utf-8");

        // Parse frontmatter for name/description
        const frontmatter = parseFrontmatter(content);
        const name = frontmatter.name || entry.name.replace(/\.md$/, "");
        const description = frontmatter.description || "";

        skills.push({
          name,
          description,
          tier,
          filePath,
          overriddenBy: null,
        });
      } else if (entry.isDirectory()) {
        // Check for index.md or skill.md inside directory
        const indexPath = path.join(dir, entry.name, "index.md");
        const skillPath = path.join(dir, entry.name, "skill.md");
        const targetPath = fs.existsSync(indexPath)
          ? indexPath
          : fs.existsSync(skillPath)
            ? skillPath
            : null;

        if (targetPath) {
          const content = fs.readFileSync(targetPath, "utf-8");
          const frontmatter = parseFrontmatter(content);
          skills.push({
            name: frontmatter.name || entry.name,
            description: frontmatter.description || "",
            tier,
            filePath: targetPath,
            overriddenBy: null,
          });
        }
      }
    }
  } catch {
    // Directory doesn't exist or isn't readable
  }

  return skills;
}

function parseFrontmatter(content: string): Record<string, string> {
  const match = content.match(/^---\n([\s\S]*?)\n---/);
  if (!match) return {};

  const result: Record<string, string> = {};
  for (const line of match[1].split("\n")) {
    const [key, ...rest] = line.split(":");
    if (key && rest.length > 0) {
      result[key.trim()] = rest.join(":").trim();
    }
  }
  return result;
}

