// src/shell/store/settings.ts

import type { Pin, PinMode, PinType, StatusBarField } from "../../shared/types.js";
import { v4 as uuid } from "uuid";
import { config } from "../../shared/config.js";

export interface SettingsSlice {
  pins: Record<string, Pin[]>; // keyed by tabId
  statusBarFields: StatusBarField[];

  addPin: (tabId: string, type: PinType, target: string, mode: PinMode) => void;
  removePin: (tabId: string, pinId: string) => void;
  clearOneShots: (tabId: string) => void;
  getPins: (tabId: string) => Pin[];

  setStatusBarFields: (fields: StatusBarField[]) => void;
  toggleStatusBarField: (key: string) => void;
}

export function createSettingsSlice(
  set: (fn: (state: any) => any) => void,
  get: () => any
): SettingsSlice {
  return {
    pins: {},
    statusBarFields: [...config.defaultStatusBarFields],

    addPin: (tabId: string, type: PinType, target: string, mode: PinMode) => {
      const pin: Pin = {
        id: uuid(),
        sessionId: tabId,
        type,
        target,
        mode,
        createdAt: Date.now(),
      };
      set((s: any) => ({
        pins: {
          ...s.pins,
          [tabId]: [...(s.pins[tabId] || []), pin],
        },
      }));
    },

    removePin: (tabId: string, pinId: string) => {
      set((s: any) => ({
        pins: {
          ...s.pins,
          [tabId]: (s.pins[tabId] || []).filter((p: Pin) => p.id !== pinId),
        },
      }));
    },

    clearOneShots: (tabId: string) => {
      set((s: any) => ({
        pins: {
          ...s.pins,
          [tabId]: (s.pins[tabId] || []).filter((p: Pin) => p.mode !== "prompt"),
        },
      }));
    },

    getPins: (tabId: string) => {
      return get().pins[tabId] || [];
    },

    setStatusBarFields: (fields: StatusBarField[]) =>
      set(() => ({ statusBarFields: fields })),

    toggleStatusBarField: (key: string) => {
      set((s: any) => ({
        statusBarFields: s.statusBarFields.map((f: StatusBarField) =>
          f.key === key ? { ...f, enabled: !f.enabled } : f
        ),
      }));
    },
  };
}
