// src/worker/context-manager.ts

import fs from "node:fs";
import path from "node:path";
import { v4 as uuid } from "uuid";
import { config } from "../shared/config.js";

export class ContextManager {
  private cwd: string;

  constructor(cwd: string) {
    this.cwd = cwd;
  }

  async createSnapshot(
    sessionId: string,
    messages: Array<{ role: string; content: string }>,
    pins: Array<{ type: string; target: string; mode: string }>
  ): Promise<{ filePath: string; summary: string }> {
    // Build a summary from messages (last 20 messages)
    const recent = messages.slice(-20);
    const conversationText = recent
      .map((m) => `${m.role}: ${m.content.slice(0, 200)}`)
      .join("\n");

    const summary = this.buildSummary(conversationText);

    // Save to memory file
    const snapshotDir = config.snapshotDir(this.cwd);
    fs.mkdirSync(snapshotDir, { recursive: true });

    const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
    const fileName = `snapshot-${timestamp}.md`;
    const filePath = path.join(snapshotDir, fileName);

    const content = `---
name: Session Snapshot ${timestamp}
description: Conversation snapshot from clui session ${sessionId}
type: project
---

## Summary

${summary}

## Context State

**Active pins:**
${pins.map((p) => `- [${p.mode}] ${p.type}: ${p.target}`).join("\n") || "None"}

## Key Messages

${recent.map((m) => `**${m.role}:** ${m.content.slice(0, 500)}`).join("\n\n")}
`;

    fs.writeFileSync(filePath, content, "utf-8");

    return { filePath, summary };
  }

  private buildSummary(conversationText: string): string {
    // Simple extractive summary — take first and last user messages
    const lines = conversationText.split("\n");
    const userLines = lines.filter((l) => l.startsWith("user:"));

    if (userLines.length === 0) return "Empty conversation.";
    if (userLines.length === 1) return userLines[0].replace("user: ", "");

    return `Started with: "${userLines[0].replace("user: ", "").slice(0, 100)}"\nEnded with: "${userLines[userLines.length - 1].replace("user: ", "").slice(0, 100)}"`;
  }
}
```

