import { useEffect, useCallback } from "react";
import fs from "node:fs";
import path from "node:path";
import { useStore } from "../store/index.js";
import { config } from "../../shared/config.js";
import type { Skill, SkillTier } from "../../shared/types.js";

function scanSkillDir(dir: string, tier: SkillTier): Skill[] {
  const skills: Skill[] = [];

  try {
    if (!fs.existsSync(dir)) return skills;

    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isFile() && entry.name.endsWith(".md")) {
        const filePath = path.join(dir, entry.name);
        const content = fs.readFileSync(filePath, "utf-8");

        const frontmatter = parseFrontmatter(content);
        const name = frontmatter.name || entry.name.replace(/\.md$/, "");
        const description = frontmatter.description || "";

        skills.push({ name, description, tier, filePath, overriddenBy: null });
      } else if (entry.isDirectory()) {
        const indexPath = path.join(dir, entry.name, "index.md");
        const skillPath = path.join(dir, entry.name, "skill.md");
        const targetPath = fs.existsSync(indexPath)
          ? indexPath
          : fs.existsSync(skillPath)
            ? skillPath
            : null;

        if (targetPath) {
          const content = fs.readFileSync(targetPath, "utf-8");
          const frontmatter = parseFrontmatter(content);
          skills.push({
            name: frontmatter.name || entry.name,
            description: frontmatter.description || "",
            tier,
            filePath: targetPath,
            overriddenBy: null,
          });
        }
      }
    }
  } catch {
    // Directory doesn't exist or isn't readable
  }

  return skills;
}

function parseFrontmatter(content: string): Record<string, string> {
  const match = content.match(/^---\n([\s\S]*?)\n---/);
  if (!match) return {};

  const result: Record<string, string> = {};
  for (const line of match[1].split("\n")) {
    const [key, ...rest] = line.split(":");
    if (key && rest.length > 0) {
      result[key.trim()] = rest.join(":").trim();
    }
  }
  return result;
}

function markOverrides(skills: Skill[]): Skill[] {
  const nameToHighestTier = new Map<string, SkillTier>();
  const tierPriority: Record<SkillTier, number> = { repo: 0, user: 1, global: 2 };

  for (const skill of skills) {
    const existing = nameToHighestTier.get(skill.name);
    if (!existing || tierPriority[skill.tier] < tierPriority[existing]) {
      nameToHighestTier.set(skill.name, skill.tier);
    }
  }

  return skills.map((skill) => {
    const highestTier = nameToHighestTier.get(skill.name)!;
    if (skill.tier !== highestTier) {
      return { ...skill, overriddenBy: highestTier };
    }
    return skill;
  });
}

export function useSkillDiscovery(cwd: string): {
  refresh: () => void;
} {
  const setSkills = useStore((s) => s.setSkills);

  const refresh = useCallback(() => {
    const repoSkills = scanSkillDir(config.skillDirs.repo(cwd), "repo");
    const userSkills = scanSkillDir(config.skillDirs.user, "user");
    const globalSkills = scanSkillDir(config.skillDirs.global, "global");

    const all = markOverrides([...repoSkills, ...userSkills, ...globalSkills]);
    setSkills(all);
  }, [cwd, setSkills]);

  useEffect(() => {
    refresh();
  }, [refresh]);

  return { refresh };
}
