import { useEffect, useCallback, useState } from "react";
import simpleGit from "simple-git";
import { useStore } from "../store/index.js";

export function useGit(cwd: string) {
  const activeTabId = useStore((s) => s.activeTabId);
  const updateTabStatus = useStore((s) => s.updateTabStatus);

  const refresh = useCallback(async () => {
    if (!activeTabId) return;

    try {
      const git = simpleGit(cwd);
      const isRepo = await git.checkIsRepo();
      if (!isRepo) {
        updateTabStatus(activeTabId, { gitBranch: null, gitDiffStats: null });
        return;
      }

      const [branch, diff] = await Promise.all([
        git.revparse(["--abbrev-ref", "HEAD"]),
        git.diffStat(),
      ]);

      updateTabStatus(activeTabId, {
        gitBranch: branch.trim(),
        gitDiffStats: {
          added: diff.insertions,
          removed: diff.deletions,
          modified: diff.files_changed,
        },
      });
    } catch {
      updateTabStatus(activeTabId, { gitBranch: null, gitDiffStats: null });
    }
  }, [cwd, activeTabId, updateTabStatus]);

  useEffect(() => {
    refresh();
    const interval = setInterval(refresh, 10000);
    return () => clearInterval(interval);
  }, [refresh]);

  return { refresh };
}
