import React from "react";
import { Box, Text } from "ink";
import { useStore } from "../store/index.js";
import type { Skill, SkillTier } from "../../shared/types.js";

interface SkillsSidebarProps {
  visible: boolean;
  onPinSkill: (skill: Skill, mode: "prompt" | "sticky") => void;
}

const TIER_LABELS: Record<SkillTier, string> = {
  repo: "Repo",
  user: "User",
  global: "Global",
};

const TIER_COLORS: Record<SkillTier, string> = {
  repo: "green",
  user: "blue",
  global: "magenta",
};

function SkillRow({
  skill,
  onPin,
}: {
  skill: Skill;
  onPin: (mode: "prompt" | "sticky") => void;
}): React.ReactElement {
  const isOverridden = skill.overriddenBy !== null;

  return (
    <Box flexDirection="row" paddingLeft={2}>
      <Text color={isOverridden ? "gray" : "white"} dimColor={isOverridden}>
        {isOverridden ? "[ ]" : "[x]"} {skill.name}
      </Text>
      {!isOverridden && (
        <Text color="gray"> [pin]</Text>
      )}
    </Box>
  );
}

export function SkillsSidebar({
  visible,
  onPinSkill,
}: SkillsSidebarProps): React.ReactElement {
  const skills = useStore((s) => s.skills);
  const expandedTiers = useStore((s) => s.expandedTiers);

  if (!visible) return <></>;

  const tiers: SkillTier[] = ["repo", "user", "global"];

  return (
    <Box flexDirection="column" padding={1}>
      <Text bold color="cyan">Skills</Text>

      {tiers.map((tier) => {
        const tierSkills = skills.filter((s) => s.tier === tier);
        const isExpanded = expandedTiers[tier];

        return (
          <Box key={tier} flexDirection="column" marginTop={1}>
            <Box>
              <Text color={TIER_COLORS[tier]} bold>
                {isExpanded ? "v" : ">"} {TIER_LABELS[tier]}{" "}
              </Text>
              <Text color="gray">({tierSkills.length})</Text>
            </Box>

            {isExpanded &&
              tierSkills.map((skill) => (
                <SkillRow
                  key={`${skill.tier}-${skill.name}`}
                  skill={skill}
                  onPin={(mode) => onPinSkill(skill, mode)}
                />
              ))}

            {isExpanded && tierSkills.length === 0 && (
              <Text color="gray" dimColor>
                {"  "}No skills found
              </Text>
            )}
          </Box>
        );
      })}

      <Box marginTop={1}>
        <Text color="gray" dimColor>
          1/2/3 toggle tier
        </Text>
      </Box>
    </Box>
  );
}

