2	import type {
3	  ShellToWorkerMessage,
4	  WorkerToShellMessage,
5	  IPCMessage,
6	} from "../shared/ipc.js";
7	import { ClaudeBridge } from "./claude-bridge.js";
8	import type net from "node:net";
9	
10	const workerId = process.argv[2];
11	const cwd = process.argv[3] || process.cwd();
12	
13	if (!workerId) {
14	  console.error("Worker requires workerId as first argument");
15	  process.exit(1);
16	}
17	
18	let socket: net.Socket;
19	let bridge: ClaudeBridge;
20	
21	function send(msg: WorkerToShellMessage): void {
22	  sendMessage(socket, msg);
23	}
24	
25	async function handleMessage(msg: IPCMessage): Promise<void> {
26	  const m = msg as ShellToWorkerMessage;
27	
28	  switch (m.type) {
29	    case "send_prompt":
30	      await bridge.sendPrompt(m.prompt, m.pins);
31	      break;
32	
33	    case "context_reset":
34	      bridge = createBridge();
35	      send({ type: "status_update", data: { contextTokens: 0, contextPercent: 0 } });
36	      break;
37	
38	    case "shutdown":
39	      bridge.interrupt();
40	      socket.end();
41	      process.exit(0);
42	      break;
43	
44	    default:
45	      send({ type: "error", message: `Unknown message type: ${(m as any).type}`, fatal: false });
46	  }
47	}
48	
49	function createBridge(): ClaudeBridge {
50	  return new ClaudeBridge(
51	    {
52	      onStreamChunk: (content) => send({ type: "stream_chunk", content }),
53	      onMessageComplete: (role, content, tokens, cost) =>
54	        send({ type: "message_complete", role, content, tokens, cost }),
