import React, { useEffect, useState } from "react";
import { Box, useInput } from "ink";
import { Layout } from "./shell/components/Layout.js";
import { TabBar } from "./shell/components/TabBar.js";
import { ChatView } from "./shell/components/ChatView.js";
import { InputBar } from "./shell/components/InputBar.js";
import { StatusBar } from "./shell/components/StatusBar.js";
import { ContextBar } from "./shell/components/ContextBar.js";
import { SessionSidebar } from "./shell/components/SessionSidebar.js";
import { SkillsSidebar } from "./shell/components/SkillsSidebar.js";
import { useStore } from "./shell/store/index.js";
import { useWorkerManager } from "./shell/hooks/useWorkerManager.js";
import { useSessions } from "./shell/hooks/useSessions.js";
import { useSkillDiscovery } from "./shell/hooks/useSkillDiscovery.js";
import { useGit } from "./shell/hooks/useGit.js";
import type { CliArgs } from "./cli/index.js";

interface AppProps {
  args: CliArgs;
}

export function App({ args }: AppProps): React.ReactElement {
  const createTab = useStore((s) => s.createTab);
  const activeTabId = useStore((s) => s.activeTabId);
  const tabs = useStore((s) => s.tabs);
  const addPin = useStore((s) => s.addPin);
  const removePin = useStore((s) => s.removePin);
  const clearOneShots = useStore((s) => s.clearOneShots);
  const statusBarFields = useStore((s) => s.statusBarFields);
  const activePins = useStore((s) =>
    s.activeTabId ? s.getPins(s.activeTabId) : []
  );

  const [initialized, setInitialized] = useState(false);
  const [sidebarVisible, setSidebarVisible] = useState({
    sessions: true,
    skills: true,
  });

  const { spawnWorker, sendPrompt, killWorker } = useWorkerManager(args.cwd);
  useSessions();
  useSkillDiscovery(args.cwd);
  useGit(args.cwd);

  // Create initial tab and spawn its worker
  useEffect(() => {
    if (!initialized) {
      const tab = createTab("New Session");
      spawnWorker(tab.id);
      setInitialized(true);
    }
  }, [initialized, createTab, spawnWorker]);

  // Spawn worker when new tab is created
  useEffect(() => {
    for (const tab of tabs) {
      if (!tab.workerId && !tab.workerReady) {
        spawnWorker(tab.id);
      }
    }
  }, [tabs, spawnWorker]);

  // Sidebar toggle hotkeys
  useInput((input, key) => {
    if (input === "h" && key.ctrl) {
      setSidebarVisible((v) => ({ ...v, sessions: !v.sessions }));
    }
    if (input === "s" && key.ctrl) {
      setSidebarVisible((v) => ({ ...v, skills: !v.skills }));
    }
  });

  function handleSubmit(text: string): void {
    if (!activeTabId) return;

    // Extract @file references
    const fileMatches = text.match(/@(\S+)/g) || [];
    for (const match of fileMatches) {
      addPin(activeTabId, "file", match.slice(1), "prompt");
    }

    // Extract /skill references
    const skillMatches = text.match(/\/(\S+)/g) || [];
    for (const match of skillMatches) {
      addPin(activeTabId, "skill", match.slice(1), "prompt");
    }

    // Clean prompt text
    const cleanText = text
      .replace(/@\S+/g, "")
      .replace(/\/\S+/g, "")
      .trim();

    if (cleanText) {
      const currentPins = useStore.getState().getPins(activeTabId);
      sendPrompt(activeTabId, cleanText, currentPins);
      clearOneShots(activeTabId);
    }
  }

  return (
    <Layout
      sessionSidebar={
        <SessionSidebar
          onOpenSession={(session) => {
            const tab = createTab(session.name);
            spawnWorker(tab.id);
          }}
          visible={sidebarVisible.sessions}
        />
      }
      center={
        <Box flexDirection="column" flexGrow={1}>
          <TabBar />
          <ChatView />
          <ContextBar
            pins={activePins}
            onRemovePin={(pinId) => {
              if (activeTabId) removePin(activeTabId, pinId);
            }}
          />
          <InputBar onSubmit={handleSubmit} />
          <StatusBar fields={statusBarFields} />
        </Box>
      }
      skillsSidebar={
        <SkillsSidebar
          visible={sidebarVisible.skills}
          onPinSkill={(skill, mode) => {
            if (activeTabId) {
              addPin(activeTabId, "skill", skill.name, mode);
            }
          }}
        />
      }
    />
  );
}

