import React, { useEffect, useState } from "react";
import { Box, Text } from "ink";
import { Layout } from "./shell/components/Layout.js";
import { TabBar } from "./shell/components/TabBar.js";
import { ChatView } from "./shell/components/ChatView.js";
import { InputBar } from "./shell/components/InputBar.js";
import { StatusBar } from "./shell/components/StatusBar.js";
import { ContextBar } from "./shell/components/ContextBar.js";
import { useStore } from "./shell/store/index.js";
import { useWorkerManager } from "./shell/hooks/useWorkerManager.js";
import type { CliArgs } from "./cli/index.js";

interface AppProps {
  args: CliArgs;
}

export function App({ args }: AppProps): React.ReactElement {
  const createTab = useStore((s) => s.createTab);
  const activeTabId = useStore((s) => s.activeTabId);
  const tabs = useStore((s) => s.tabs);
  const [initialized, setInitialized] = useState(false);

  const { spawnWorker, sendPrompt, killWorker } = useWorkerManager(args.cwd);

  // Create initial tab and spawn its worker
  useEffect(() => {
    if (!initialized) {
      const tab = createTab("New Session");
      spawnWorker(tab.id);
      setInitialized(true);
    }
  }, [initialized, createTab, spawnWorker]);

  // Spawn worker when new tab is created (watch for tabs without workers)
  useEffect(() => {
    for (const tab of tabs) {
      if (!tab.workerId && !tab.workerReady) {
        spawnWorker(tab.id);
      }
    }
  }, [tabs, spawnWorker]);

  function handleSubmit(text: string): void {
    if (!activeTabId) return;
    sendPrompt(activeTabId, text, []);
  }

  function handleCloseTab(tabId: string): void {
    killWorker(tabId);
    useStore.getState().closeTab(tabId);
  }

  return (
    <Layout
      sessionSidebar={
        <Box flexDirection="column" padding={1}>
          <Text bold color="cyan">Sessions</Text>
          <Text color="gray">Phase 3</Text>
        </Box>
      }
      center={
        <Box flexDirection="column" flexGrow={1}>
          <TabBar />
          <ChatView />
          <ContextBar pins={[]} onRemovePin={() => {}} />
          <InputBar onSubmit={handleSubmit} />
          <StatusBar />
        </Box>
      }
      skillsSidebar={
        <Box flexDirection="column" padding={1}>
          <Text bold color="cyan">Skills</Text>
          <Text color="gray">Phase 4</Text>
        </Box>
      }
    />
  );
}

