```typescript
// src/worker/worktree-manager.ts

import simpleGit, { type SimpleGit } from "simple-git";
import path from "node:path";

export interface WorktreeInfo {
  path: string;
  branch: string;
}

export interface DiffStats {
  added: number;
  removed: number;
  modified: number;
}

export class WorktreeManager {
  private git: SimpleGit;
  private cwd: string;

  constructor(cwd: string) {
    this.cwd = cwd;
    this.git = simpleGit(cwd);
  }

  async createWorktree(branch: string): Promise<WorktreeInfo> {
    const worktreePath = path.join(
      path.dirname(this.cwd),
      "worktrees",
      `${path.basename(this.cwd)}-${branch}`
    );

    // Create branch if it doesn't exist
    try {
      await this.git.branch([branch]);
    } catch {
      // Branch may already exist
    }

    await this.git.raw(["worktree", "add", worktreePath, branch]);

    return { path: worktreePath, branch };
  }

  async removeWorktree(worktreePath: string): Promise<void> {
    await this.git.raw(["worktree", "remove", worktreePath, "--force"]);
  }

  async getBranch(worktreePath?: string): Promise<string | null> {
    try {
      const git = worktreePath ? simpleGit(worktreePath) : this.git;
      const status = await git.status();
      return status.current;
    } catch {
      return null;
    }
  }

  async getDiffStats(worktreePath?: string): Promise<DiffStats | null> {
    try {
      const git = worktreePath ? simpleGit(worktreePath) : this.git;
      const diff = await git.diffSummary();

      return {
        added: diff.insertions,
        removed: diff.deletions,
        modified: diff.files.length,
      };
    } catch {
      return null;
    }
  }

  async isGitRepo(): Promise<boolean> {
    try {
      await this.git.status();
      return true;
    } catch {
      return false;
    }
  }
}
```

