        <Box key={idx}>
          <Text color="gray">
            {new Date(event.timestamp).toLocaleTimeString()} --{" "}
            {event.trigger} -- {event.preTokens.toLocaleString()} tokens before
          </Text>
        </Box>
      ))}
      <Text color="gray" dimColor>Press 'x' to collapse</Text>
    </Box>
  );
}

