import React from "react";
import { Box, Static, Text } from "ink";
import { useStore } from "../store/index.js";
import type { Message } from "../../shared/types.js";

function MessageBubble({ msg }: { msg: Message }): React.ReactElement {
  const color = msg.role === "user" ? "green" : msg.role === "assistant" ? "white" : "gray";
  const prefix = msg.role === "user" ? "> " : "  ";

  return (
    <Box flexDirection="column" marginBottom={1}>
      <Text color={color} dimColor={msg.role === "system"}>
        {prefix}
        {msg.content}
      </Text>
    </Box>
  );
}

export function ChatView(): React.ReactElement {
  const activeTabId = useStore((s) => s.activeTabId);
  const messages = useStore((s) =>
    activeTabId ? s.tabMessages[activeTabId] || [] : []
  );
  const streamBuffer = useStore((s) =>
    activeTabId ? s.tabStreamBuffer[activeTabId] || "" : ""
  );

  return (
    <Box flexDirection="column" flexGrow={1} paddingX={1}>
      <Static items={messages}>
        {(msg) => <MessageBubble key={msg.id} msg={msg} />}
      </Static>

      {streamBuffer.length > 0 && (
        <Box>
          <Text color="white">  {streamBuffer}</Text>
          <Text color="cyan">|</Text>
        </Box>
      )}

      {messages.length === 0 && streamBuffer.length === 0 && (
        <Box justifyContent="center" alignItems="center" flexGrow={1}>
          <Text color="gray">Start a conversation...</Text>
        </Box>
      )}
    </Box>
  );
}

