import { useEffect, useCallback } from "react";
import { useStore } from "../store/index.js";
import type { Session } from "../../shared/types.js";
import * as db from "../../shared/db.js";

async function loadClaudeSessions(): Promise<Session[]> {
  try {
    const sdk = await import("@anthropic-ai/claude-agent-sdk");
    const listSessions = (sdk as any).listSessions;
    if (!listSessions) return [];
    const sdkSessions = await listSessions({ limit: 100 });

    return sdkSessions.map((s: any) => ({
      id: s.sessionId || s.id,
      claudeSessionId: s.sessionId || s.id,
      name: s.title || s.name || `Session ${(s.sessionId || s.id)?.slice(0, 8)}`,
      color: null,
      repoPath: s.cwd || null,
      worktreePath: null,
      worktreeBranch: null,
      model: s.model || null,
      totalTokens: 0,
      totalCost: 0,
      durationSeconds: 0,
      status: "closed" as const,
      createdAt: s.createdAt || Date.now(),
      updatedAt: s.updatedAt || Date.now(),
    }));
  } catch {
    return [];
  }
}

export function useSessions(): {
  refresh: () => Promise<void>;
} {
  const setSessions = useStore((s) => s.setSessions);

  const refresh = useCallback(async () => {
    const [sdkSessions, dbSessions] = await Promise.all([
      loadClaudeSessions(),
      Promise.resolve(db.listSessions(100)),
    ]);

    const dbMap = new Map(dbSessions.map((s) => [s.claudeSessionId || s.id, s]));

    const merged: Session[] = [];
    const seen = new Set<string>();

    for (const sdkSession of sdkSessions) {
      const dbOverride = dbMap.get(sdkSession.id);
      if (dbOverride) {
        merged.push({
          ...sdkSession,
          name: dbOverride.name || sdkSession.name,
          color: dbOverride.color || sdkSession.color,
        });
      } else {
        merged.push(sdkSession);
      }
      seen.add(sdkSession.id);
    }

    for (const dbSession of dbSessions) {
      if (!seen.has(dbSession.claudeSessionId || dbSession.id)) {
        merged.push(dbSession);
      }
    }

    merged.sort((a, b) => b.updatedAt - a.updatedAt);
    setSessions(merged);
  }, [setSessions]);

  useEffect(() => {
    refresh();
  }, [refresh]);

  return { refresh };
}

